import React, { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
  FiArrowLeft, FiActivity, FiTarget, FiZap,
  FiTrendingUp, FiMessageSquare, FiBell, FiShield, FiClock,
  FiMap, FiAward
} from 'react-icons/fi';

// Modular feature components
import DecayTracker from '../components/SkillDetails/DecayTracker';
import RoleRoadmap from '../components/SkillDetails/RoleRoadmap';
import GapForecast from '../components/SkillDetails/GapForecast';
import SkillRecommendations from '../components/SkillDetails/SkillRecommendations';
import ROIEstimation from '../components/SkillDetails/ROIEstimation';
import AIMentorChat from '../components/SkillDetails/AIMentorChat';
import TrendAlerts from '../components/SkillDetails/TrendAlerts';
import ResilienceScore from '../components/SkillDetails/ResilienceScore';

const SkillDetails: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('decay');

  const features = [
    { id: 'decay', label: 'Skill Decay Tracker', icon: <FiClock /> },
    { id: 'roadmap', label: 'Future Role & Roadmap', icon: <FiMap /> },
    { id: 'gap', label: 'Skill Gap Forecast', icon: <FiActivity /> },
    { id: 'recommend', label: 'Priority Recommendations', icon: <FiTarget /> },
    { id: 'roi', label: 'Learning ROI', icon: <FiTrendingUp /> },
    { id: 'mentor', label: 'AI Mentor', icon: <FiMessageSquare /> },
    { id: 'alerts', label: 'Trend Alerts', icon: <FiBell /> },
    { id: 'resilience', label: 'Resilience Score', icon: <FiShield /> },
  ];

  const renderContent = () => {
    switch (activeTab) {
      case 'decay':
        return <DecayTracker />;
      case 'roadmap':
        return <RoleRoadmap />;
      case 'gap':
        return <GapForecast />;
      case 'recommend':
        return <SkillRecommendations />;
      case 'roi':
        return <ROIEstimation />;
      case 'mentor':
        return <AIMentorChat />;
      case 'alerts':
        return <TrendAlerts />;
      case 'resilience':
        return <ResilienceScore />;
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen bg-[#0f172a] text-white relative overflow-hidden">
      {/* Background Elements */}
      <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-blue-600/10 rounded-full blur-[120px]"></div>
      <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-indigo-600/10 rounded-full blur-[120px]"></div>

      {/* Top Nav / Toolbar */}
      <nav className="bg-slate-900/50 backdrop-blur-md border-b border-slate-800 sticky top-0 z-20 shadow-lg">
        <div className="max-w-7xl mx-auto px-4 overflow-x-auto">
          <div className="flex items-center h-16 whitespace-nowrap scrollbar-hide">
            <button
              onClick={() => navigate('/skills')}
              className="mr-6 p-2 hover:bg-slate-800 rounded-lg text-slate-400 hover:text-white transition-colors"
            >
              <FiArrowLeft size={20} />
            </button>
            <div className="flex gap-1">
              {features.map((feature) => (
                <button
                  key={feature.id}
                  onClick={() => setActiveTab(feature.id)}
                  className={`flex items-center gap-2 px-4 py-2 rounded-lg font-medium transition-all duration-200 ${
                    activeTab === feature.id
                      ? 'bg-blue-600 text-white shadow-lg shadow-blue-500/20'
                      : 'text-slate-400 hover:text-white hover:bg-slate-800/50'
                  }`}
                >
                  {feature.icon}
                  <span>{feature.label}</span>
                </button>
              ))}
            </div>
          </div>
        </div>
      </nav>

      {/* Header with Skill Name */}
      <div className="relative border-b border-slate-800 bg-slate-900/20 backdrop-blur-sm z-10">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
          <div className="flex items-center gap-4 mb-3 opacity-80">
            <div className="bg-yellow-500/20 p-2 rounded-lg">
               <FiAward className="text-yellow-400" size={20} />
            </div>
            <span className="text-xs font-bold uppercase tracking-[0.2em] text-blue-400">Detailed Analytics</span>
          </div>
          <h1 className="text-4xl md:text-5xl font-extrabold tracking-tight text-white capitalize drop-shadow-sm">
            {id?.replace(/-/g, ' ')}
          </h1>
          <p className="mt-3 text-slate-400 max-w-2xl text-lg font-light">
            Deep dive into your career trajectory, market value, and AI-driven growth path for this specific skill.
          </p>
        </div>
      </div>

      {/* Main Content Area */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10 relative z-10">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
          {/* Active Feature Content */}
          <div className="lg:col-span-8">
            {renderContent()}
          </div>

          {/* Side Overview / Quick Context */}
          <div className="lg:col-span-4 space-y-6">
            <div className="bg-slate-900/60 backdrop-blur-md p-6 rounded-2xl shadow-xl border border-slate-800">
              <h4 className="font-bold text-white mb-6 flex items-center gap-2">
                 <FiActivity className="text-blue-400" /> Market Context
              </h4>
              <div className="space-y-4">
